/**
 * bundle-game.js
 *
 * index.html を読み込み、ローカルJSファイルをすべてインライン化して
 * src/gameHtml.js に export default 文字列として出力する。
 *
 * Firebase CDN スクリプトはそのまま残す（実行時にネットから読み込み）。
 * アプリ向けの最小修正も同時に適用する。
 */
const fs = require('fs');
const path = require('path');

const rootDir = path.join(__dirname, '..');
const htmlPath = path.join(rootDir, 'index.html');
const outPath = path.join(rootDir, 'src', 'gameHtml.js');

let html = fs.readFileSync(htmlPath, 'utf8');

// === アプリ向け修正 ===

// 1. PWAマニフェストリンクを削除
html = html.replace(/<link rel="manifest"[^>]*>\n?/, '');

// 2. アイコン生成スクリプトを削除（16-102行目相当）
html = html.replace(/<script>\n\(function\(\)\{\n\s*var c=document\.createElement\('canvas'\)[\s\S]*?\}\)\(\);\n<\/script>\n/, '');

// 3. ゲストログインの注意書きテキスト変更
html = html.replace(
  '※ゲストデータはブラウザに保存されます',
  '※ゲストデータは端末に保存されます'
);
html = html.replace(
  'キャッシュ削除等でデータが消失する場合があります',
  'アプリ削除でデータが消失する場合があります'
);

// === ローカルJSファイルをインライン化 ===
html = html.replace(
  /<script src="js\/([^"?]+)(\?[^"]*)?"><\/script>/g,
  (match, filename) => {
    const jsPath = path.join(rootDir, 'js', filename);
    if (!fs.existsSync(jsPath)) {
      console.error(`Warning: ${jsPath} not found, keeping original tag`);
      return match;
    }
    const jsContent = fs.readFileSync(jsPath, 'utf8');
    return `<script>\n${jsContent}\n</script>`;
  }
);

// === エスケープしてJSモジュールとして出力 ===
const escaped = html
  .replace(/\\/g, '\\\\')
  .replace(/`/g, '\\`')
  .replace(/\$\{/g, '\\${');

// テンプレートリテラルで展開するとエスケープが壊れるので文字列結合で出力
const output = '// Auto-generated by scripts/bundle-game.js — do not edit manually\nexport default `' + escaped + '`;\n';

// src/ ディレクトリがなければ作成
const outDir = path.dirname(outPath);
if (!fs.existsSync(outDir)) {
  fs.mkdirSync(outDir, { recursive: true });
}

fs.writeFileSync(outPath, output, 'utf8');

const sizeKB = (Buffer.byteLength(output, 'utf8') / 1024).toFixed(1);
console.log(`✓ Bundled game HTML → ${outPath} (${sizeKB} KB)`);
